import { useEffect } from "react";
import { NavLink, useLocation } from "react-router-dom";
import {
  LayoutDashboard,
  UserPlus,
  Users,
  IndianRupeeIcon,
  GraduationCap,
  LogOut,
} from "lucide-react";
import { useAuth } from "@/hooks/useAuth";
import { Button } from "@/components/ui/button";

import {
  Sidebar,
  SidebarContent,
  SidebarGroup,
  SidebarGroupContent,
  SidebarGroupLabel,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
  useSidebar,
} from "@/components/ui/sidebar";
import { cn } from "@/lib/utils";

const navigationItems = [
  { title: "Dashboard", url: "/", icon: LayoutDashboard },
  { title: "Registration", url: "/registration", icon: UserPlus },
  { title: "Student Profiles", url: "/profiles", icon: Users },
  { title: "Fees Due", url: "/fees-due", icon: IndianRupeeIcon },
];

export function AppSidebar() {
  const sidebar = useSidebar() as any;
  const { state } = sidebar;
  const location = useLocation();
  const { signOut, user } = useAuth();
  const currentPath = location.pathname;
  const collapsed = state === "collapsed";

  // Auto-close on mobile
  const closeSidebarOnMobile = () => {
    if (typeof window !== "undefined" && window.matchMedia("(max-width: 767px)").matches) {
      sidebar?.setOpenMobile?.(false);
      sidebar?.setOpen?.(false);
      if (!sidebar?.setOpenMobile && !sidebar?.setOpen && typeof sidebar?.toggleSidebar === "function") {
        sidebar.toggleSidebar();
      }
    }
  };

  // Close on route change (mobile)
  useEffect(() => {
    closeSidebarOnMobile();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [location.pathname]);

  const handleSignOut = async () => {
    await signOut();
    closeSidebarOnMobile();
  };

  const isActive = (path: string) => currentPath === path;

  // Bigger comfy buttons on mobile; compact on desktop
  const getNavCls = ({ isActive }: { isActive: boolean }) =>
    cn(
      // Mobile
      "group flex items-center gap-3 rounded-xl h-12 px-4 text-base font-medium active:scale-[.98] transition-all duration-200",
      // Desktop override
      "md:h-9 md:px-3 md:text-sm",
      isActive
        ? "bg-sidebar-primary text-sidebar-primary-foreground shadow-md ring-1 ring-sidebar-primary/30"
        : "hover:bg-sidebar-accent hover:text-sidebar-accent-foreground"
    );

  return (
    // Mobile par width hammesha w-64 rakhenge (text visible), desktop par collapse work karega
    <Sidebar className={cn(collapsed ? "md:w-16 w-64" : "w-64")} collapsible="icon">
      <SidebarContent className="bg-sidebar border-r border-sidebar-border">
        {/* Header */}
        <div className="flex items-center gap-2 px-4 py-6 border-b border-sidebar-border">
          <div className="w-9 h-9 bg-gradient-primary rounded-lg flex items-center justify-center">
            <GraduationCap className="w-5 h-5 text-white" />
          </div>
          {/* Text: mobile par kabhi hide nahi, desktop par collapse hone par hide */}
          <div className={cn(collapsed && "md:hidden")}>
            <h1 className="font-bold text-sidebar-foreground">Mess Manager</h1>
            <p className="text-xs text-muted-foreground">Admin Panel</p>
          </div>
        </div>

        <SidebarGroup className="px-4 py-4">
          <SidebarGroupLabel className="text-muted-foreground text-xs uppercase tracking-wider mb-4">
            Navigation
          </SidebarGroupLabel>
          <SidebarGroupContent>
            <SidebarMenu className="space-y-2">
              {navigationItems.map((item) => (
                <SidebarMenuItem key={item.title}>
                  <SidebarMenuButton asChild>
                    <NavLink
                      to={item.url}
                      end
                      className={getNavCls}
                      onClick={closeSidebarOnMobile}
                      title={collapsed ? item.title : undefined}
                    >
                      <item.icon className="w-6 h-6 shrink-0 md:w-5 md:h-5" />
                      {/* Text: mobile par visible even if collapsed; desktop par collapse pe hide */}
                      <span className={cn("ml-1", collapsed && "md:hidden")}>{item.title}</span>
                    </NavLink>
                  </SidebarMenuButton>
                </SidebarMenuItem>
              ))}
            </SidebarMenu>
          </SidebarGroupContent>
        </SidebarGroup>

        {/* Admin Info */}
        <div className="mt-auto px-4 py-4 border-t border-sidebar-border space-y-4">
          {/* Text: mobile par visible even if collapsed; desktop par collapse pe hide */}
          <div className={cn("flex items-center gap-3", collapsed && "md:hidden")}>
            <div className="w-9 h-9 bg-gradient-primary rounded-full flex items-center justify-center">
              <span className="text-white text-sm font-medium">
                {user?.email?.charAt(0).toUpperCase() || "A"}
              </span>
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-sm font-medium text-sidebar-foreground truncate">Admin User</p>
              <p className="text-xs text-muted-foreground truncate">
                {user?.email || "admin@messmanager.com"}
              </p>
            </div>
          </div>

          <Button
            variant="ghost"
            size="sm"
            onClick={handleSignOut}
            className={cn(
              // Mobile: bigger touch target + left aligned
              "w-full justify-start gap-2 text-muted-foreground hover:text-foreground rounded-xl h-12 text-base",
              // Desktop: compact
              "md:h-9 md:text-sm",
              // Desktop collapsed me center, mobile par nahi
              collapsed && "md:justify-center"
            )}
            title={collapsed ? "Sign Out" : undefined}
          >
            <LogOut className="h-5 w-5 md:h-4 md:w-4" />
            <span className={cn(collapsed && "md:hidden")}>Sign Out</span>
          </Button>
        </div>
      </SidebarContent>
    </Sidebar>
  );
}

import React, { useEffect, useState } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Separator } from "@/components/ui/separator";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Calendar } from "@/components/ui/calendar";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Edit, Trash2, Phone, MessageCircle, Save, X, Calendar as CalendarIcon, User, Users, CreditCard, AlertCircle } from "lucide-react";
import { toast } from "sonner";
import { format } from "date-fns";
import { cn } from "@/lib/utils";
import { calculateDueDate, getDaysUntilDue } from "@/lib/dateUtils";
import { validatePhone, validateName, validateEnrollmentNumber, sanitizeInput } from "@/lib/validation";
import { supabase } from "@/integrations/supabase/client";

interface Student {
  id: string;
  name: string;
  phone: string;
  fatherName: string;
  fatherPhone: string;
  branch: string;
  enrollmentNumber: string;
  registrationDate: string;
  photo: string;
  feesStatus: "paid" | "pending" | "overdue";
  feesAmount: number;
  daysUntilDue: number;
  dueDate?: string;
  lastPaymentDate?: string;
  transactions: {
    id: string;
    date: string;
    amount: number;
    type: "cash" | "online";
    status: "completed" | "pending";
  }[];
}

interface StudentProfileModalProps {
  student: Student | null;
  isOpen: boolean;
  onClose: () => void;
  onEdit: (student: Student) => void;
  onDelete: (studentId: string) => void;
}

const branches = ["Computer Science", "Electronics", "Mechanical", "Civil", "Electrical"];

export function StudentProfileModal({ student, isOpen, onClose, onEdit, onDelete }: StudentProfileModalProps) {
  const [isEditing, setIsEditing] = useState(false);
  const [editedStudent, setEditedStudent] = useState<Student | null>(null);
  const [validationErrors, setValidationErrors] = useState<Record<string, string>>({});
  const [payments, setPayments] = useState<Array<{ id: string; date: string; amount: number; type: "cash" | "online"; status: "completed" | "pending" }>>([]);
  const [isSavingPayment, setIsSavingPayment] = useState(false);
  const [newPayment, setNewPayment] = useState<{ amount: string; method: "cash" | "online"; status: "completed" | "pending" }>({ amount: "", method: "cash", status: "completed" });
  const [isPhotoPreviewOpen, setIsPhotoPreviewOpen] = useState(false);

  React.useEffect(() => {
    if (student) {
      setEditedStudent({ ...student });
    }
  }, [student]);

  useEffect(() => {
    const fetchPayments = async () => {
      if (!student) return;
      const { data, error } = await supabase
        .from('payments')
        .select('*')
        .eq('student_id', student.id)
        .order('paid_at', { ascending: false });
      if (error) {
        if ((error as any)?.code === '42P01') {
          toast.error('Payments table not found. Please apply the latest Supabase migration.');
        } else {
          toast.error('Failed to load payments: ' + error.message);
        }
        return;
      }
      setPayments((data || []).map((p) => ({
        id: p.id,
        date: p.paid_at,
        amount: Number(p.amount) || 0,
        type: p.method,
        status: p.status,
      })));
    };
    fetchPayments();
  }, [student?.id]);

  if (!student || !editedStudent) return null;

  const handleEdit = () => {
    setIsEditing(true);
    setValidationErrors({});
  };

  const validateForm = (): boolean => {
    const errors: Record<string, string> = {};
    
    if (editedStudent) {
      const nameValidation = validateName(editedStudent.name, 'Student name');
      if (!nameValidation.isValid) errors.name = nameValidation.error!;
      
      const phoneValidation = validatePhone(editedStudent.phone);
      if (!phoneValidation.isValid) errors.phone = phoneValidation.error!;
      
      const fatherNameValidation = validateName(editedStudent.fatherName, "Father's name");
      if (!fatherNameValidation.isValid) errors.fatherName = fatherNameValidation.error!;
      
      const fatherPhoneValidation = validatePhone(editedStudent.fatherPhone);
      if (!fatherPhoneValidation.isValid) errors.fatherPhone = fatherPhoneValidation.error!;
      
      const enrollmentValidation = validateEnrollmentNumber(editedStudent.enrollmentNumber);
      if (!enrollmentValidation.isValid) errors.enrollmentNumber = enrollmentValidation.error!;
      
      if (!editedStudent.branch) errors.branch = 'Branch is required';
      if (editedStudent.feesAmount < 0) errors.feesAmount = 'Fees amount cannot be negative';
    }
    
    setValidationErrors(errors);
    return Object.keys(errors).length === 0;
  };

  const handleSave = () => {
    if (!validateForm()) {
      toast.error("Please fix the validation errors before saving");
      return;
    }
    
    if (editedStudent) {
      // Recalculate due date and days until due when saving
      const dueDate = calculateDueDate(editedStudent.registrationDate);
      const daysUntilDue = getDaysUntilDue(dueDate);
      
      const updatedStudent = {
        ...editedStudent,
        dueDate,
        daysUntilDue,
      };
      
      onEdit(updatedStudent);
      setIsEditing(false);
      toast.success("Student profile updated successfully!");
    }
  };

  const handleCancel = () => {
    setEditedStudent({ ...student });
    setIsEditing(false);
    setValidationErrors({});
  };

  const handleDelete = () => {
    if (window.confirm(`Are you sure you want to delete ${student.name}'s profile? This action cannot be undone.`)) {
      onDelete(student.id);
      onClose();
      toast.success("Student profile deleted successfully!");
    }
  };

  const handleCall = () => {
    window.open(`tel:${student.phone}`, '_self');
  };

  const handleWhatsApp = () => {
    const message = `Hello ${student.name}, this is a reminder about your mess fees. Please make the payment at your earliest convenience. Thank you!`;
    window.open(`https://wa.me/${student.phone}?text=${encodeURIComponent(message)}`, '_blank');
  };

  const handleInputChange = (field: keyof Student, value: string | number) => {
    if (editedStudent) {
      const sanitizedValue = typeof value === 'string' ? sanitizeInput(value) : value;
      setEditedStudent({ ...editedStudent, [field]: sanitizedValue });
      
      // Clear validation error when user starts typing
      if (validationErrors[field]) {
        setValidationErrors(prev => ({ ...prev, [field]: '' }));
      }
    }
  };

  const getStatusBadge = (status: string) => {
    const variants = {
      paid: "bg-emerald-500/10 text-emerald-600 border-emerald-500/20",
      pending: "bg-amber-500/10 text-amber-600 border-amber-500/20",
      overdue: "bg-red-500/10 text-red-600 border-red-500/20"
    };
    return variants[status as keyof typeof variants] || variants.pending;
  };

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-[95vw] sm:max-w-4xl max-h-[95vh] overflow-y-auto p-4 sm:p-6">
        <DialogHeader>
          <DialogTitle className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3">
            <span className="text-lg sm:text-xl">Student Profile</span>
            <div className="flex gap-2 flex-wrap">
              {!isEditing ? (
                <>
                  <Button variant="outline" size="sm" onClick={handleEdit} className="flex-1 sm:flex-none">
                    <Edit className="h-4 w-4 mr-1" />
                    <span className="hidden xs:inline">Edit</span>
                  </Button>
                  <Button variant="destructive" size="sm" onClick={handleDelete} className="flex-1 sm:flex-none">
                    <Trash2 className="h-4 w-4 mr-1" />
                    <span className="hidden xs:inline">Delete</span>
                  </Button>
                </>
              ) : (
                <>
                  <Button variant="outline" size="sm" onClick={handleCancel} className="flex-1 sm:flex-none">
                    <X className="h-4 w-4 mr-1" />
                    <span className="hidden xs:inline">Cancel</span>
                  </Button>
                  <Button size="sm" onClick={handleSave} className="flex-1 sm:flex-none">
                    <Save className="h-4 w-4 mr-1" />
                    <span className="hidden xs:inline">Save</span>
                  </Button>
                </>
              )}
            </div>
          </DialogTitle>
        </DialogHeader>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-4 sm:gap-6">
          {/* Left Column - Basic Info */}
          <div className="lg:col-span-2 space-y-4 sm:space-y-6">
            <Card>
              <CardHeader className="p-4 sm:p-6">
                <CardTitle className="flex items-center gap-2 text-base sm:text-lg">
                  <User className="h-4 w-4 sm:h-5 sm:w-5" />
                  Personal Information
                </CardTitle>
              </CardHeader>
              <CardContent className="p-4 sm:p-6 pt-0 space-y-4">
                <div className="flex flex-col sm:flex-row items-start sm:items-center gap-4">
                  <Avatar className="h-16 w-16 sm:h-20 sm:w-20 self-center sm:self-start cursor-zoom-in" onClick={() => setIsPhotoPreviewOpen(true)}>
                    <AvatarImage src={student.photo} alt={student.name} />
                    <AvatarFallback className="text-lg">{student.name.split(' ').map(n => n[0]).join('')}</AvatarFallback>
                  </Avatar>
                  <div className="flex-1 w-full sm:w-auto text-center sm:text-left">
                    {isEditing ? (
                      <Input
                        value={editedStudent.name}
                        onChange={(e) => handleInputChange('name', e.target.value)}
                        className={cn("text-lg font-semibold mb-2", validationErrors.name && "border-destructive")}
                      />
                    ) : (
                      <h3 className="text-lg font-semibold">{student.name}</h3>
                    )}
                    {validationErrors.name && (
                      <p className="text-sm text-destructive flex items-center gap-1">
                        <AlertCircle className="h-4 w-4" />
                        {validationErrors.name}
                      </p>
                    )}
                    <p className="text-muted-foreground">{student.enrollmentNumber}</p>
                  </div>
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  <div>
                    <Label>Phone Number</Label>
                    {isEditing ? (
                      <Input
                        value={editedStudent.phone}
                        onChange={(e) => handleInputChange('phone', e.target.value)}
                        className={validationErrors.phone ? "border-destructive" : ""}
                      />
                    ) : (
                      <p className="font-medium">{student.phone}</p>
                    )}
                    {validationErrors.phone && (
                      <p className="text-sm text-destructive flex items-center gap-1 mt-1">
                        <AlertCircle className="h-4 w-4" />
                        {validationErrors.phone}
                      </p>
                    )}
                  </div>
                  <div>
                    <Label>Branch</Label>
                    {isEditing ? (
                      <Select
                        value={editedStudent.branch}
                        onValueChange={(value) => handleInputChange('branch', value)}
                      >
                        <SelectTrigger className={validationErrors.branch ? "border-destructive" : ""}>
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                          {branches.map((branch) => (
                            <SelectItem key={branch} value={branch}>{branch}</SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                    ) : (
                      <p className="font-medium">{student.branch}</p>
                    )}
                    {validationErrors.branch && (
                      <p className="text-sm text-destructive flex items-center gap-1 mt-1">
                        <AlertCircle className="h-4 w-4" />
                        {validationErrors.branch}
                      </p>
                    )}
                  </div>
                  <div>
                    <Label>Father's Name</Label>
                    {isEditing ? (
                      <Input
                        value={editedStudent.fatherName}
                        onChange={(e) => handleInputChange('fatherName', e.target.value)}
                        className={validationErrors.fatherName ? "border-destructive" : ""}
                      />
                    ) : (
                      <p className="font-medium">{student.fatherName}</p>
                    )}
                    {validationErrors.fatherName && (
                      <p className="text-sm text-destructive flex items-center gap-1 mt-1">
                        <AlertCircle className="h-4 w-4" />
                        {validationErrors.fatherName}
                      </p>
                    )}
                  </div>
                  <div>
                    <Label>Father's Phone</Label>
                    {isEditing ? (
                      <Input
                        value={editedStudent.fatherPhone}
                        onChange={(e) => handleInputChange('fatherPhone', e.target.value)}
                        className={validationErrors.fatherPhone ? "border-destructive" : ""}
                      />
                    ) : (
                      <p className="font-medium">{student.fatherPhone}</p>
                    )}
                    {validationErrors.fatherPhone && (
                      <p className="text-sm text-destructive flex items-center gap-1 mt-1">
                        <AlertCircle className="h-4 w-4" />
                        {validationErrors.fatherPhone}
                      </p>
                    )}
                  </div>
                </div>

                <Separator />

                <div className="flex flex-col sm:flex-row gap-3 sm:gap-4">
                  <Button onClick={handleCall} className="flex-1 h-11">
                    <Phone className="h-4 w-4 mr-2" />
                    Call Student
                  </Button>
                  <Button onClick={handleWhatsApp} variant="outline" className="flex-1 h-11">
                    <MessageCircle className="h-4 w-4 mr-2" />
                    WhatsApp
                  </Button>
                </div>
              </CardContent>
            </Card>

            {/* Transaction History */}
            <Card>
              <CardHeader className="p-4 sm:p-6">
                <CardTitle className="flex items-center gap-2 text-base sm:text-lg">
                  <CreditCard className="h-4 w-4 sm:h-5 sm:w-5" />
                  Payment History
                </CardTitle>
              </CardHeader>
              <CardContent className="p-4 sm:p-6 pt-0">
                {payments.length > 0 ? (
                  <div className="space-y-3">
                    {payments.map((transaction) => (
                      <div key={transaction.id} className="flex items-center justify-between p-3 rounded-lg border">
                        <div className="min-w-0 flex-1">
                          <p className="font-medium text-sm sm:text-base">₹{transaction.amount}</p>
                          <p className="text-xs sm:text-sm text-muted-foreground truncate">
                            {new Date(transaction.date).toLocaleDateString()} • {transaction.type}
                          </p>
                        </div>
                        <Badge variant={transaction.status === "completed" ? "default" : "secondary"} className="ml-2 flex-shrink-0">
                          {transaction.status}
                        </Badge>
                      </div>
                    ))}
                  </div>
                ) : (
                  <p className="text-muted-foreground text-center py-6 text-sm">No payment history available</p>
                )}
                <div className="mt-4 p-3 border rounded-lg space-y-3">
                  <div className="flex gap-2">
                    <div className="flex-1">
                      <Label>Amount</Label>
                      <Input type="number" min="0" step="0.01" value={newPayment.amount} onChange={(e) => setNewPayment((p) => ({ ...p, amount: e.target.value }))} />
                    </div>
                    <div className="w-40">
                      <Label>Method</Label>
                      <Select value={newPayment.method} onValueChange={(v: "cash" | "online") => setNewPayment((p) => ({ ...p, method: v }))}>
                        <SelectTrigger>
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="cash">Cash</SelectItem>
                          <SelectItem value="online">Online</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                    <div className="w-40">
                      <Label>Status</Label>
                      <Select value={newPayment.status} onValueChange={(v: "completed" | "pending") => setNewPayment((p) => ({ ...p, status: v }))}>
                        <SelectTrigger>
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="completed">Completed</SelectItem>
                          <SelectItem value="pending">Pending</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                  </div>
                  <div className="flex justify-end">
                    <Button
                      onClick={async () => {
                        if (!student) return;
                        const amountNum = Number(newPayment.amount);
                        if (!amountNum || amountNum <= 0) {
                          toast.error("Enter a valid amount");
                          return;
                        }
                        // Ensure user is authenticated for RLS policies
                        const { data: userResult } = await supabase.auth.getUser();
                        if (!userResult?.user) {
                          toast.error('You must be signed in to record a payment.');
                          return;
                        }
                        setIsSavingPayment(true);
                        const { error } = await supabase.from('payments').insert({
                          student_id: student.id,
                          amount: amountNum,
                          method: newPayment.method,
                          status: newPayment.status,
                        });
                        setIsSavingPayment(false);
                        if (error) {
                          if ((error as any)?.code === '42501') {
                            toast.error('Not authorized to record payments. Check RLS policies.');
                          } else if ((error as any)?.code === '42P01') {
                            toast.error('Payments table not found. Please apply the latest Supabase migration.');
                          } else {
                            toast.error("Failed to record payment: " + error.message);
                          }
                          return;
                        }
                        toast.success("Payment recorded");
                        setNewPayment({ amount: "", method: "cash", status: "completed" });
                        // Refresh payments and let parent refresh list on next open
                        const { data } = await supabase
                          .from('payments')
                          .select('*')
                          .eq('student_id', student.id)
                          .order('paid_at', { ascending: false });
                        setPayments((data || []).map((p) => ({
                          id: p.id,
                          date: p.paid_at,
                          amount: Number(p.amount) || 0,
                          type: p.method,
                          status: p.status,
                        })));
                      }}
                      disabled={isSavingPayment}
                    >
                      {isSavingPayment ? 'Saving...' : 'Record Payment'}
                    </Button>
                  </div>
                </div>
              </CardContent>
            </Card>
          </div>

          {/* Right Column - Status & Actions */}
          <div className="space-y-4 sm:space-y-6">
            <Card>
              <CardHeader className="p-4 sm:p-6">
                <CardTitle className="flex items-center gap-2 text-base sm:text-lg">
                  <CalendarIcon className="h-4 w-4 sm:h-5 sm:w-5" />
                  Registration Info
                </CardTitle>
              </CardHeader>
              <CardContent className="p-4 sm:p-6 pt-0 space-y-4">
                <div>
                  <Label>Enrollment Number</Label>
                  {isEditing ? (
                    <Input
                      value={editedStudent.enrollmentNumber}
                      onChange={(e) => handleInputChange('enrollmentNumber', e.target.value.toUpperCase())}
                      className={validationErrors.enrollmentNumber ? "border-destructive" : ""}
                    />
                  ) : (
                    <p className="font-medium">{student.enrollmentNumber}</p>
                  )}
                  {validationErrors.enrollmentNumber && (
                    <p className="text-sm text-destructive flex items-center gap-1 mt-1">
                      <AlertCircle className="h-4 w-4" />
                      {validationErrors.enrollmentNumber}
                    </p>
                  )}
                </div>
                <div>
                  <Label>Registration Date</Label>
                  {isEditing ? (
                    <Popover>
                      <PopoverTrigger asChild>
                        <Button
                          variant={"outline"}
                          className={cn(
                            "w-full justify-start text-left font-normal",
                            !editedStudent.registrationDate && "text-muted-foreground"
                          )}
                        >
                          <CalendarIcon className="mr-2 h-4 w-4" />
                          {editedStudent.registrationDate ? format(new Date(editedStudent.registrationDate), "PPP") : <span>Pick a date</span>}
                        </Button>
                      </PopoverTrigger>
                      <PopoverContent className="w-auto p-0" align="start">
                        <Calendar
                          mode="single"
                          selected={editedStudent.registrationDate ? new Date(editedStudent.registrationDate) : undefined}
                          onSelect={(date) => {
                            if (date) {
                              setEditedStudent({ 
                                ...editedStudent, 
                                registrationDate: date.toISOString().split('T')[0] 
                              });
                              // Clear validation error
                              if (validationErrors.registrationDate) {
                                setValidationErrors(prev => ({ ...prev, registrationDate: '' }));
                              }
                            }
                          }}
                          initialFocus
                          className={cn("p-3 pointer-events-auto")}
                        />
                      </PopoverContent>
                    </Popover>
                  ) : (
                    <p className="font-medium">{new Date(student.registrationDate).toLocaleDateString()}</p>
                  )}
                </div>
                <div>
                  <Label>Due Date</Label>
                  <p className="font-medium text-primary">
                    {student.dueDate ? new Date(student.dueDate).toLocaleDateString() : 
                     new Date(calculateDueDate(student.registrationDate)).toLocaleDateString()}
                  </p>
                </div>
                <div>
                  <Label>Fees Amount</Label>
                  {isEditing ? (
                    <Input
                      type="number"
                      min="0"
                      step="0.01"
                      value={editedStudent.feesAmount}
                      onChange={(e) => handleInputChange('feesAmount', Number(e.target.value))}
                      className={validationErrors.feesAmount ? "border-destructive" : ""}
                    />
                  ) : (
                    <p className="font-medium">₹{student.feesAmount}</p>
                  )}
                  {validationErrors.feesAmount && (
                    <p className="text-sm text-destructive flex items-center gap-1 mt-1">
                      <AlertCircle className="h-4 w-4" />
                      {validationErrors.feesAmount}
                    </p>
                  )}
                </div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="p-4 sm:p-6">
                <CardTitle className="text-base sm:text-lg">Fees Status</CardTitle>
              </CardHeader>
              <CardContent className="p-4 sm:p-6 pt-0 space-y-4">
                <div className="flex items-center justify-between">
                  <span className="text-sm sm:text-base">Status</span>
                  <Badge className={getStatusBadge(student.feesStatus)}>
                    {student.feesStatus}
                  </Badge>
                </div>
                <div className="flex items-center justify-between">
                  <span className="text-sm sm:text-base">Amount Due</span>
                  <span className="font-semibold text-sm sm:text-base">₹{student.feesAmount}</span>
                </div>
                <div className="flex items-center justify-between">
                  <span className="text-sm sm:text-base">Days Until Due</span>
                  <span className={`font-semibold text-sm sm:text-base ${student.daysUntilDue <= 3 ? 'text-red-600' : student.daysUntilDue <= 7 ? 'text-amber-600' : 'text-green-600'}`}>
                    {student.daysUntilDue} days
                  </span>
                </div>
                {student.lastPaymentDate && (
                  <div className="flex items-center justify-between">
                    <span className="text-sm sm:text-base">Last Payment</span>
                    <span className="text-xs sm:text-sm text-muted-foreground">
                      {new Date(student.lastPaymentDate).toLocaleDateString()}
                    </span>
                  </div>
                )}
              </CardContent>
            </Card>
          </div>
        </div>
      </DialogContent>
      {/* Fullscreen Photo Preview */}
      <Dialog open={isPhotoPreviewOpen} onOpenChange={setIsPhotoPreviewOpen}>
        <DialogContent className="max-w-[95vw] max-h-[95vh] p-2 sm:p-4">
          <div className="w-full h-full flex items-center justify-center">
            <img
              src={student?.photo || ''}
              alt={student?.name || 'Student'}
              className="max-w-full max-h-[80vh] rounded-md"
              onClick={() => setIsPhotoPreviewOpen(false)}
            />
          </div>
        </DialogContent>
      </Dialog>
    </Dialog>
  );
}

