                </div>

                {/* Avatar: hidden on mobile, shown on desktop */}
                <div className="hidden md:flex w-12 h-12 bg-muted rounded-full items-center justify-center overflow-hidden">
                  {student.photo ? (
                    <img 
                      src={student.photo} 
                      alt={student.name} 
                      className="w-full h-full object-cover"
                      onError={(e) => {
                        const target = e.target as HTMLImageElement;
                        target.style.display = 'none';
                        target.parentElement!.innerHTML = `<span class="text-muted-foreground font-medium">${student.name.split(' ').map(n => n[0]).join('')}</span>`;
                      }}
                    />
                  ) : (
                    <span className="text-muted-foreground font-medium">
                      {student.name.split(' ').map(n => n[0]).join('')}
                    </span>
                  )}
                </div>

                {/* Details */}
                <div className="w-full md:flex-1 min-w-0">
                  <div className="flex items-center gap-3 mb-2">
                    <h3 className="font-semibold text-base sm:text-lg text-foreground truncate">{student.name}</h3>
                    {/* Inline badge only on md+ */}
                    <div className="hidden md:block">
                      {getDaysOverdueBadge(student.daysOverdue)}
                    </div>
                  </div>
                  <div className="grid gap-x-4 gap-y-1 text-sm text-muted-foreground md:grid-cols-3">
                    <div className="truncate">
                      <span className="font-medium text-foreground/80">Enrollment:</span> {student.enrollmentNumber}
                    </div>
                    {/* Branch removed on mobile */}
                    <div className="hidden md:block truncate">
                      <span className="font-medium text-foreground/80">Branch:</span> {student.branch}
                    </div>
                    <div className="whitespace-nowrap">
                      <span className="font-medium text-foreground/80">Due Date:</span>{" "}
                      {student.dueDate !== 'N/A' 
                        ? format(new Date(student.dueDate), 'dd MMM, yyyy')
                        : 'Not Set'}
                    </div>
                  </div>
                </div>

                {/* Actions */}
                <div className="md:text-right space-y-3">
                  <div>
                    <p className="text-sm text-muted-foreground">Amount Due</p>
                    <p className="text-xl font-bold text-destructive">
                      {formatAmount(student.amountDue)}
                    </p>
                  </div>

                  {/* Mobile: Call + WhatsApp small and on one line */}
                  <div className="flex items-center gap-2 md:justify-end">
                    <Button
                      size="sm"
                      variant="outline"
                      className="h-8 px-2 text-xs w-auto md:h-8 md:px-3 md:text-sm"
                      onClick={() => handleCall(student.phone)}
                      disabled={!student.phone || student.phone === 'N/A'}
                    >
                      <Phone className="w-4 h-4 mr-2" /> Call
                    </Button>
                    <Button
                      size="sm"
                      variant="outline"
                      className="h-8 px-2 text-xs w-auto md:h-8 md:px-3 md:text-sm"
                      onClick={() => handleWhatsApp(student)}
                      disabled={!student.phone || student.phone === 'N/A'}
                    >
                      <MessageSquare className="w-4 h-4 mr-2" /> WhatsApp
                    </Button>
                  </div>

                  {/* Keep Pay separate; full-width on mobile, inline on md+ */}
                  <div className="flex">
                    <Button
                      size="sm"
                      className="h-10 w-full md:h-8 md:w-auto md:ml-auto"
                      onClick={() => handleRecordPayment(student.id)}
                    >
                      <DollarSign className="w-4 h-4 mr-2" /> Pay
                    </Button>
                  </div>
                </div>
              </div>

              <div className="mt-4 md:pl-[64px]">
                <div className="flex items-center justify-between text-xs text-muted-foreground mb-1">
                  <span>Urgency Level</span>
                  <span>{student.daysOverdue} days overdue</span>
                </div>
                <Progress 
                  value={Math.min((student.daysOverdue / 30) * 100, 100)} 
                  className="h-2" 
                />
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {!loading && filteredStudents.length === 0 && (
        <Card className="shadow-card bg-gradient-card">
          <CardContent className="py-12 text-center">
            <DollarSign className="w-12 h-12 mx-auto text-muted-foreground mb-4" />
            <h3 className="text-lg font-medium text-foreground mb-2">All Clear!</h3>
            <p className="text-muted-foreground">
              {searchTerm 
                ? "No students found matching your search." 
                : "No students have pending payments at the moment."}
            </p>
          </CardContent>
        </Card>
      )}
    </div>
  );
};

export default FeesDue;

import { useState, useEffect } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Calendar } from "@/components/ui/calendar";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Command, CommandEmpty, CommandGroup, CommandInput, CommandItem, CommandList } from "@/components/ui/command";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { cn } from "@/lib/utils";
import { format, addMonths } from "date-fns";
import { 
  CalendarIcon, Camera, Upload, User, Phone, GraduationCap, Save, X, Loader2, AlertCircle, ChevronsUpDown, Utensils
} from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/hooks/useAuth";
import { useToast } from "@/hooks/use-toast";
import { 
  validatePhone, validateName, validateEnrollmentNumber, validateFile, sanitizeInput
} from "@/lib/validation";

const Registration = () => {
  const { user } = useAuth();
  const { toast } = useToast();
  
  // --- States for Date Pickers ---
  const [registrationDate, setRegistrationDate] = useState<Date>();
  const [dueDate, setDueDate] = useState<Date>();

  const [photoPreview, setPhotoPreview] = useState<string | null>(null);
  const [photoFile, setPhotoFile] = useState<File | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formData, setFormData] = useState({ 
    fullName: "", 
    phone: "", 
    fatherName: "", 
    fatherPhone: "", 
    branch: "", 
    enrollmentNumber: "",
    shift: "" // NEW: Added shift field
  });
  const [validationErrors, setValidationErrors] = useState<Record<string, string>>({});
  const [comboboxOpen, setComboboxOpen] = useState(false);

  const branches = ["Computer Science", "Electronics & Comm.", "Mechanical", "Civil", "Electrical", "Information Technology"];
  
  // NEW: Shift options
  const shiftOptions = [
    { value: "lunch", label: "Lunch Only" },
    { value: "dinner", label: "Dinner Only" },
    { value: "both", label: "Both (Lunch & Dinner)" }
  ];

  // --- Automatically set due date when registration date is selected ---
  useEffect(() => {
    if (registrationDate) {
      setDueDate(addMonths(registrationDate, 1));
    }
  }, [registrationDate]);

  const handleInputChange = (field: string, value: string) => {
    const fieldType = (field === 'fullName' || field === 'fatherName') ? 'name' : 'default';
    const sanitizedValue = fieldType === 'name' ? value : sanitizeInput(value);
    setFormData(prev => ({ ...prev, [field]: sanitizedValue }));
    if (validationErrors[field]) setValidationErrors(prev => ({ ...prev, [field]: '' }));
  };

  const handlePhotoUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const fileValidation = validateFile(file);
      if (!fileValidation.isValid) {
        toast({ title: "Invalid File", description: fileValidation.error, variant: "destructive" });
        event.target.value = '';
        return;
      }
      setPhotoFile(file);
      const reader = new FileReader();
      reader.onloadend = () => setPhotoPreview(reader.result as string);
      reader.readAsDataURL(file);
      setValidationErrors(prev => ({ ...prev, photo: '' }));
    }
  };

  const validateForm = (): boolean => {
    const errors: Record<string, string> = {};
    const nameValidation = validateName(formData.fullName, 'Full name');
    if (!nameValidation.isValid) errors.fullName = nameValidation.error!;
    const phoneValidation = validatePhone(formData.phone);
    if (!phoneValidation.isValid) errors.phone = phoneValidation.error!;
    const fatherNameValidation = validateName(formData.fatherName, "Father's name");
    if (!fatherNameValidation.isValid) errors.fatherName = fatherNameValidation.error!;
    const fatherPhoneValidation = validatePhone(formData.fatherPhone);
    if (!fatherPhoneValidation.isValid) errors.fatherPhone = fatherPhoneValidation.error!;
    const enrollmentValidation = validateEnrollmentNumber(formData.enrollmentNumber);
    if (!enrollmentValidation.isValid) errors.enrollmentNumber = enrollmentValidation.error!;
    if (!formData.branch) errors.branch = 'Branch is required';
    if (!formData.shift) errors.shift = 'Shift selection is required'; // NEW: Validation for shift
    if (!registrationDate) errors.registrationDate = 'Registration date is required';
    if (!dueDate) errors.dueDate = 'Fee due date is required';
    setValidationErrors(errors);
    return Object.keys(errors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) { toast({ title: "Error", description: "You must be logged in.", variant: "destructive" }); return; }
    if (!validateForm()) { toast({ title: "Validation Error", description: "Please fix the errors in the form.", variant: "destructive" }); return; }

    setIsSubmitting(true);
    try {
      let photoUrl = null;
      if (photoFile) {
        const fileExt = photoFile.name.split('.').pop();
        const fileName = `${formData.enrollmentNumber}_${Date.now()}.${fileExt}`;
        const { error: uploadError } = await supabase.storage.from('student-photos').upload(fileName, photoFile);
        if (uploadError) throw uploadError;
        const { data } = supabase.storage.from('student-photos').getPublicUrl(fileName);
        photoUrl = data.publicUrl;
      }

      // Added shift to the insert payload
      const { error: insertError } = await supabase.from('students').insert({
        enrollment_number: formData.enrollmentNumber,
        name: formData.fullName.trim(),
        phone: formData.phone,
        father_name: formData.fatherName.trim(),
        father_phone: formData.fatherPhone,
        branch: formData.branch,
        shift: formData.shift, // NEW: Save shift
        registration_date: registrationDate!.toISOString().split('T')[0],
        due_date: dueDate!.toISOString().split('T')[0],
        photo_url: photoUrl,
        created_by: user.id,
      });

      if (insertError) throw insertError;
      toast({ title: "Success", description: "Student registered successfully!" });
      handleClearForm();
    } catch (error: any) {
      toast({ title: "Error", description: error.message || "Failed to register student.", variant: "destructive" });
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleClearForm = () => {
    setFormData({ fullName: "", phone: "", fatherName: "", fatherPhone: "", branch: "", enrollmentNumber: "", shift: "" });
    setRegistrationDate(undefined);
    setDueDate(undefined);
    setPhotoPreview(null);
    setPhotoFile(null);
    setValidationErrors({});
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6 px-4 pb-8 sm:px-0">
      <div>
        <h1 className="text-3xl font-bold text-foreground">Student Registration</h1>
        <p className="text-muted-foreground">Add new student details to the system</p>
      </div>

      <form onSubmit={handleSubmit}>
        <div className="grid gap-6 grid-cols-1 lg:grid-cols-3">
          <div className="lg:col-span-2 space-y-6">
            <Card className="shadow-card bg-gradient-card">
              <CardHeader><CardTitle className="flex items-center gap-2"><User className="w-5 h-5" /> Personal Information</CardTitle><CardDescription>Basic details of the student</CardDescription></CardHeader>
              <CardContent className="space-y-4">
                 <div className="grid gap-4 grid-cols-1 md:grid-cols-2">
                  <div className="space-y-2">
                    <Label htmlFor="fullName">Full Name *</Label>
                    <Input id="fullName" placeholder="Enter student's full name" value={formData.fullName} onChange={(e) => handleInputChange("fullName", e.target.value)} className={validationErrors.fullName ? "border-destructive" : ""} required />
                    {validationErrors.fullName && <p className="text-sm text-destructive flex items-center gap-1 mt-1"><AlertCircle className="h-4 w-4" /> {validationErrors.fullName}</p>}
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="phone">Phone Number *</Label>
                    <Input id="phone" placeholder="+91 xxxxx xxxxx" value={formData.phone} onChange={(e) => handleInputChange("phone", e.target.value)} className={validationErrors.phone ? "border-destructive" : ""} required />
                    {validationErrors.phone && <p className="text-sm text-destructive flex items-center gap-1 mt-1"><AlertCircle className="h-4 w-4" /> {validationErrors.phone}</p>}
                  </div>
                </div>
                <div className="grid gap-4 grid-cols-1 md:grid-cols-2">
                   <div className="space-y-2">
                    <Label htmlFor="fatherName">Father's Name *</Label>
                    <Input id="fatherName" placeholder="Enter father's full name" value={formData.fatherName} onChange={(e) => handleInputChange("fatherName", e.target.value)} className={validationErrors.fatherName ? "border-destructive" : ""} required />
                    {validationErrors.fatherName && <p className="text-sm text-destructive flex items-center gap-1 mt-1"><AlertCircle className="h-4 w-4" /> {validationErrors.fatherName}</p>}
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="fatherPhone">Father's Phone Number *</Label>
                    <Input id="fatherPhone" placeholder="+91 xxxxx xxxxx" value={formData.fatherPhone} onChange={(e) => handleInputChange("fatherPhone", e.target.value)} className={validationErrors.fatherPhone ? "border-destructive" : ""} required />
                    {validationErrors.fatherPhone && <p className="text-sm text-destructive flex items-center gap-1 mt-1"><AlertCircle className="h-4 w-4" /> {validationErrors.fatherPhone}</p>}
                  </div>
                </div>
              </CardContent>
            </Card>
            
            <Card className="shadow-card bg-gradient-card">
              <CardHeader><CardTitle className="flex items-center gap-2"><GraduationCap className="w-5 h-5" /> Academic Information</CardTitle><CardDescription>Student's academic details</CardDescription></CardHeader>
              <CardContent className="space-y-4">
                <div className="grid gap-4 grid-cols-1 md:grid-cols-2">
                  <div className="space-y-2">
                    <Label htmlFor="branch">Branch *</Label>
                    <Popover open={comboboxOpen} onOpenChange={setComboboxOpen}>
                      <PopoverTrigger asChild>
                        <Button variant="outline" role="combobox" aria-expanded={comboboxOpen} className={cn("w-full justify-between font-normal", !formData.branch && "text-muted-foreground", validationErrors.branch && "border-destructive")}>
                          {formData.branch ? branches.find(b => b.toLowerCase() === formData.branch.toLowerCase()) || formData.branch : "Select or type branch..."}
                          <ChevronsUpDown className="ml-2 h-4 w-4 shrink-0 opacity-50" />
                        </Button>
                      </PopoverTrigger>
                      <PopoverContent className="w-[--radix-popover-trigger-width] p-0">
                        <Command>
                          <CommandInput placeholder="Search or type new branch..." onValueChange={(value) => handleInputChange("branch", value)} />
                          <CommandList>
                            <CommandEmpty>No branch found. Type to add.</CommandEmpty>
                            <CommandGroup>
                              {branches.map((branch) => (
                                <CommandItem key={branch} value={branch} onSelect={(currentValue) => { handleInputChange("branch", currentValue === formData.branch ? "" : branch); setComboboxOpen(false); }}>
                                  {branch}
                                </CommandItem>
                              ))}
                            </CommandGroup>
                          </CommandList>
                        </Command>
                      </PopoverContent>
                    </Popover>
                    {validationErrors.branch && <p className="text-sm text-destructive flex items-center gap-1 mt-1"><AlertCircle className="h-4 w-4" /> {validationErrors.branch}</p>}
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="enrollmentNumber">Enrollment Number *</Label>
                    <Input id="enrollmentNumber" placeholder="Enter enrollment number" value={formData.enrollmentNumber} onChange={(e) => handleInputChange("enrollmentNumber", e.target.value)} className={validationErrors.enrollmentNumber ? "border-destructive" : ""} required />
                    {validationErrors.enrollmentNumber && <p className="text-sm text-destructive flex items-center gap-1 mt-1"><AlertCircle className="h-4 w-4" /> {validationErrors.enrollmentNumber}</p>}
                  </div>
                </div>
                
                {/* NEW: Shift Selection Field */}
                <div className="space-y-2">
                  <Label htmlFor="shift" className="flex items-center gap-2">
                    <Utensils className="w-4 h-4" />
                    Meal Shift *
                  </Label>
                  <Select value={formData.shift} onValueChange={(value) => handleInputChange("shift", value)}>
                    <SelectTrigger className={cn(validationErrors.shift && "border-destructive")}>
                      <SelectValue placeholder="Select meal shift" />
                    </SelectTrigger>
                    <SelectContent>
                      {shiftOptions.map((option) => (
                        <SelectItem key={option.value} value={option.value}>
                          {option.label}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  {validationErrors.shift && <p className="text-sm text-destructive flex items-center gap-1 mt-1"><AlertCircle className="h-4 w-4" /> {validationErrors.shift}</p>}
                </div>
                
                {/* Registration Date and Due Date side-by-side */}
                <div className="grid gap-4 grid-cols-1 md:grid-cols-2">
                  <div className="space-y-2">
                    <Label>Registration Date *</Label>
                    <Popover>
                      <PopoverTrigger asChild>
                        <Button variant="outline" className={cn("w-full justify-start text-left font-normal", !registrationDate && "text-muted-foreground", validationErrors.registrationDate && "border-destructive")}>
                          <CalendarIcon className="mr-2 h-4 w-4" />
                          {registrationDate ? format(registrationDate, "PPP") : "Pick registration date"}
                        </Button>
                      </PopoverTrigger>
                      <PopoverContent className="w-auto p-0" align="start">
                        <Calendar mode="single" selected={registrationDate} onSelect={setRegistrationDate} initialFocus />
                      </PopoverContent>
                    </Popover>
                    {validationErrors.registrationDate && <p className="text-sm text-destructive flex items-center gap-1 mt-1"><AlertCircle className="h-4 w-4" /> {validationErrors.registrationDate}</p>}
                  </div>

                  <div className="space-y-2">
                    <Label>First Fee Due Date *</Label>
                    <Popover>
                      <PopoverTrigger asChild>
                        <Button variant="outline" className={cn("w-full justify-start text-left font-normal", !dueDate && "text-muted-foreground", validationErrors.dueDate && "border-destructive")}>
                          <CalendarIcon className="mr-2 h-4 w-4" />
                          {dueDate ? format(dueDate, "PPP") : "Pick fee due date"}
                        </Button>
                      </PopoverTrigger>
                      <PopoverContent className="w-auto p-0" align="start">
                        <Calendar mode="single" selected={dueDate} onSelect={setDueDate} initialFocus />
                      </PopoverContent>
                    </Popover>
                    {validationErrors.dueDate && <p className="text-sm text-destructive flex items-center gap-1 mt-1"><AlertCircle className="h-4 w-4" /> {validationErrors.dueDate}</p>}
                  </div>
                </div>
              </CardContent>
            </Card>
          </div>
          
          <div className="space-y-6 lg:col-start-3">
            <Card className="shadow-card bg-gradient-card">
              <CardHeader><CardTitle className="flex items-center gap-2"><Camera className="w-5 h-5" /> Student Photo</CardTitle><CardDescription>Upload student's ID photo</CardDescription></CardHeader>
              <CardContent className="space-y-4">
                {photoPreview ? (
                  <div className="relative"><img src={photoPreview} alt="Student" className="w-full h-48 object-cover rounded-lg border" /><Button type="button" variant="destructive" size="icon" className="absolute top-2 right-2 w-6 h-6" onClick={() => { setPhotoPreview(null); setPhotoFile(null); }}><X className="w-4 h-4" /></Button></div>
                ) : (
                  <div className="border-2 border-dashed rounded-lg p-6 text-center space-y-4"><Camera className="w-12 h-12 mx-auto text-muted-foreground" /><div><p className="text-sm font-medium">Upload photo</p><p className="text-xs text-muted-foreground">JPG, PNG, WebP up to 5MB</p></div></div>
                )}
                <div className="grid grid-cols-1 gap-2">
                  <Button type="button" variant="outline" size="sm" className="relative"><Upload className="w-4 h-4 mr-2" /> Upload<input type="file" accept="image/*" onChange={handlePhotoUpload} className="absolute inset-0 opacity-0 cursor-pointer" /></Button>
                </div>
              </CardContent>
            </Card>
            <Card className="shadow-card bg-gradient-card">
              <CardContent className="pt-6">
                <div className="space-y-4">
                  <Button type="submit" className="w-full" size="lg" disabled={isSubmitting}>
                    {isSubmitting && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
                    <Save className="w-4 h-4 mr-2" /> Register Student
                  </Button>
                  <Button type="button" variant="outline" className="w-full" onClick={handleClearForm} disabled={isSubmitting}>Clear Form</Button>
                </div>
              </CardContent>
            </Card>
          </div>
        </div>
      </form>
    </div>
  );
};

export default Registration;

import { useCallback, useEffect, useMemo, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Calendar as CalendarComponent } from "@/components/ui/calendar";
import { ArrowLeft, Wallet, User, CreditCard, Loader2, Phone, MessageSquare, Edit, Trash, Download, Calculator, Calendar, ChevronLeft, ChevronRight, Edit2, Trash2, Upload, AlertCircle, Utensils } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { getDaysUntilDue } from "@/lib/dateUtils";
import { toast } from "sonner";
import { format } from 'date-fns';
import Papa from 'papaparse';

// --- TYPES ---
type PaymentMethod = "Cash" | "Online";
type PaymentStatus = "completed" | "pending";
type MealShift = "lunch" | "dinner" | "both";

interface Student { 
  id: string; 
  name: string; 
  phone: string; 
  father_name: string; 
  father_phone: string; 
  branch: string; 
  enrollment_number: string; 
  registration_date: string; 
  due_date: string; 
  photo_url?: string; 
  status: 'active' | 'fees_due' | 'inactive'; 
  fees_paid: number; 
  fees_due: number;
  shift?: MealShift;
}

interface PaymentTransaction { 
  id: string; 
  payment_date: string; 
  amount: number; 
  method: PaymentMethod; 
  status: PaymentStatus; 
  notes?: string; 
  student_id: string; 
}

interface PaymentFormState { 
  id?: string; 
  date: string; 
  amount: string; 
  method: PaymentMethod; 
  status: PaymentStatus; 
  notes: string; 
}

// --- HELPER FUNCTIONS & CONSTANTS ---
const currencyFormatter = new Intl.NumberFormat("en-IN", { style: "currency", currency: "INR", maximumFractionDigits: 0 });
const createEmptyFormState = (): PaymentFormState => ({ date: format(new Date(), "yyyy-MM-dd"), amount: "", method: "Cash", status: "completed", notes: "" });
const months = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];

// Helper function to get shift badge with colors
const getShiftBadge = (shift?: MealShift) => {
  if (!shift) return null;
  
  const shiftConfig = {
    lunch: { label: "Lunch Only", color: "bg-yellow-100 text-yellow-700 hover:bg-yellow-200" },
    dinner: { label: "Dinner Only", color: "bg-blue-100 text-blue-700 hover:bg-blue-200" },
    both: { label: "Both (Lunch & Dinner)", color: "bg-purple-100 text-purple-700 hover:bg-purple-200" }
  };
  
  const config = shiftConfig[shift];
  return (
    <Badge className={config.color}>
      <Utensils className="w-3 h-3 mr-1" />
      {config.label}
    </Badge>
  );
};

// --- SUB-COMPONENTS ---
const SummaryCards = ({ totalPaid, totalPending, totalTransactions }: { totalPaid: number, totalPending: number, totalTransactions: number }) => ( 
  <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
    <Card><CardContent className="pt-4"><div className="text-sm font-medium text-muted-foreground">Total Paid</div><div className="text-2xl font-bold text-green-600">{currencyFormatter.format(totalPaid)}</div></CardContent></Card>
    <Card><CardContent className="pt-4"><div className="text-sm font-medium text-muted-foreground">Amount Due</div><div className="text-2xl font-bold text-destructive">{currencyFormatter.format(totalPending)}</div></CardContent></Card>
    <Card><CardContent className="pt-4"><div className="text-sm font-medium text-muted-foreground">Transactions</div><div className="text-2xl font-bold">{totalTransactions}</div></CardContent></Card>
  </div> 
);

const PaymentTable = ({ transactions, onEdit, onDelete, formatAmount }: { transactions: PaymentTransaction[], onEdit: (t: PaymentTransaction) => void, onDelete: (id: string) => void, formatAmount: (n: number) => string }) => ( 
  <div className="border rounded-lg overflow-hidden bg-background"><table className="w-full text-sm"><thead className="bg-muted/50"><tr><th className="p-3 text-left">Date</th><th className="p-3 text-left">Amount</th><th className="p-3 text-left">Method</th><th className="p-3 text-left">Status</th><th className="p-3 text-right">Actions</th></tr></thead><tbody>{transactions.length === 0 ? (<tr><td colSpan={5} className="p-8 text-center text-muted-foreground">No payment history found.</td></tr>) : ( transactions.map(t => (<tr key={t.id} className="border-t"><td className="p-3">{format(new Date(t.payment_date), 'dd MMM, yyyy')}</td><td className="p-3 font-medium">{formatAmount(t.amount)}</td><td className="p-3">{t.method}</td><td className="p-3"><Badge variant={t.status === 'completed' ? 'default' : 'secondary'} className={t.status === 'completed' ? 'bg-green-100 text-green-700' : 'bg-yellow-100 text-yellow-700'}>{t.status}</Badge></td><td className="p-3 text-right"><Button variant="ghost" size="icon" onClick={() => onEdit(t)}><Edit2 className="w-4 h-4" /></Button><Button variant="ghost" size="icon" onClick={() => onDelete(t.id)}><Trash2 className="w-4 h-4 text-destructive" /></Button></td></tr>)))}</tbody></table></div>
);

const PaymentForm = ({ formState, isEditing, isSaving, onChange, onSubmit, onCancel }: { formState: PaymentFormState, isEditing: boolean, isSaving: boolean, onChange: (u: Partial<PaymentFormState>) => void, onSubmit: () => void, onCancel: () => void }) => ( 
  <div className="mt-4 p-4 border rounded-lg bg-muted/50 space-y-4"><h4 className="font-semibold">{isEditing ? "Edit Payment" : "Record New Payment"}</h4><div className="grid sm:grid-cols-4 gap-3"><div className="space-y-1"><Label htmlFor="date">Date</Label><Input id="date" type="date" value={formState.date} onChange={e => onChange({ date: e.target.value })} /></div><div className="space-y-1"><Label htmlFor="amount">Amount</Label><Input id="amount" type="number" placeholder="0.00" value={formState.amount} onChange={e => onChange({ amount: e.target.value })} /></div><div className="space-y-1"><Label>Method</Label><Select value={formState.method} onValueChange={(v: PaymentMethod) => onChange({ method: v })}><SelectTrigger><SelectValue /></SelectTrigger><SelectContent><SelectItem value="Cash">Cash</SelectItem><SelectItem value="Online">Online</SelectItem></SelectContent></Select></div><div className="space-y-1"><Label>Status</Label><Select value={formState.status} onValueChange={(v: PaymentStatus) => onChange({ status: v })}><SelectTrigger><SelectValue /></SelectTrigger><SelectContent><SelectItem value="completed">Completed</SelectItem><SelectItem value="pending">Pending</SelectItem></SelectContent></Select></div></div><div className="space-y-1"><Label htmlFor="notes">Notes (Optional)</Label><Input id="notes" placeholder="e.g., Mess fee for October" value={formState.notes} onChange={e => onChange({ notes: e.target.value })} /></div><div className="flex justify-end gap-2">{isEditing && <Button type="button" variant="ghost" onClick={onCancel}>Cancel</Button>}<Button type="button" onClick={onSubmit} disabled={isSaving}>{isSaving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}{isEditing ? "Update Payment" : "Record Payment"}</Button></div></div>
);

const EditStudentDialog = ({ isOpen, onClose, student, onSave }: { isOpen: boolean, onClose: () => void, student: Student | null, onSave: (updatedStudent: Partial<Student>, newPhoto: File | null) => void }) => { 
  const [formData, setFormData] = useState<Partial<Student>>({}); 
  const [newPhotoFile, setNewPhotoFile] = useState<File | null>(null); 
  const [photoPreview, setPhotoPreview] = useState<string | null>(null); 
  
  useEffect(() => { 
    if (student) { 
      setFormData(student); 
      setPhotoPreview(student.photo_url || null); 
    } 
  }, [student, isOpen]); 
  
  const handleChange = (field: keyof Student, value: string | Date | null) => { 
    let finalValue = value; 
    if (value instanceof Date) { 
      finalValue = format(value, 'yyyy-MM-dd'); 
    } 
    setFormData(prev => ({ ...prev, [field]: finalValue })); 
  }; 
  
  const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => { 
    const file = e.target.files?.[0]; 
    if (file) { 
      if (file.size > 5 * 1024 * 1024) {
        toast.error("Image size should be less than 5MB");
        return;
      }
      setNewPhotoFile(file); 
      setPhotoPreview(URL.createObjectURL(file)); 
    } 
  }; 
  
  const handleSaveChanges = () => { 
    onSave(formData, newPhotoFile); 
    onClose(); 
  }; 
  
  if (!student) return null; 
  
  return ( 
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="sm:max-w-[600px]">
        <DialogHeader>
          <DialogTitle>Edit Student Details</DialogTitle>
        </DialogHeader>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 py-4 max-h-[70vh] overflow-y-auto pr-2">
          <div className="space-y-2">
            <Label>Full Name</Label>
            <Input value={formData.name || ''} onChange={e => handleChange('name', e.target.value)} />
          </div>
          <div className="space-y-2">
            <Label>Enrollment Number</Label>
            <Input value={formData.enrollment_number || ''} onChange={e => handleChange('enrollment_number', e.target.value)} />
          </div>
          <div className="space-y-2">
            <Label>Phone</Label>
            <Input value={formData.phone || ''} onChange={e => handleChange('phone', e.target.value)} />
          </div>
          <div className="space-y-2">
            <Label>Father's Phone</Label>
            <Input value={formData.father_phone || ''} onChange={e => handleChange('father_phone', e.target.value)} />
          </div>
          <div className="space-y-2">
            <Label>Branch</Label>
            <Input value={formData.branch || ''} onChange={e => handleChange('branch', e.target.value)} />
          </div>
          
          <div className="space-y-2">
            <Label>Meal Shift</Label>
            <Select value={formData.shift || ''} onValueChange={(v: MealShift) => handleChange('shift', v)}>
              <SelectTrigger>
                <SelectValue placeholder="Select shift" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="lunch">Lunch Only</SelectItem>
                <SelectItem value="dinner">Dinner Only</SelectItem>
                <SelectItem value="both">Both (Lunch & Dinner)</SelectItem>
              </SelectContent>
            </Select>
          </div>
          
          <div className="space-y-2">
            <Label>Registration Date</Label>
            <Popover>
              <PopoverTrigger asChild>
                <Button variant="outline" className="w-full justify-start text-left font-normal">
                  {formData.registration_date ? format(new Date(formData.registration_date), "PPP") : "Select date"}
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-auto p-0">
                <CalendarComponent mode="single" selected={formData.registration_date ? new Date(formData.registration_date) : undefined} onSelect={(d) => d && handleChange('registration_date', d)} />
              </PopoverContent>
            </Popover>
          </div>
          <div className="space-y-2">
            <Label>Next Fee Due Date</Label>
            <Popover>
              <PopoverTrigger asChild>
                <Button variant="outline" className="w-full justify-start text-left font-normal">
                  {formData.due_date ? format(new Date(formData.due_date), "PPP") : "Select date"}
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-auto p-0">
                <CalendarComponent mode="single" selected={formData.due_date ? new Date(formData.due_date) : undefined} onSelect={(d) => d && handleChange('due_date', d)} />
              </PopoverContent>
            </Popover>
          </div>
          <div className="space-y-2">
            <Label>Status</Label>
            <Select value={formData.status} onValueChange={(v: Student['status']) => handleChange('status', v)}>
              <SelectTrigger>
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="active">Active</SelectItem>
                <SelectItem value="fees_due">Fees Due</SelectItem>
                <SelectItem value="inactive">Inactive</SelectItem>
              </SelectContent>
            </Select>
          </div>
          <div className="space-y-2 col-span-full">
            <Label>Profile Photo</Label>
            <div className="flex items-center gap-4">
              <img src={photoPreview || `https://ui-avatars.com/api/?name=${student.name}&background=random`} alt="preview" className="w-16 h-16 rounded-full object-cover"/>
              <Button type="button" variant="outline" size="sm" className="relative">
                <Upload className="w-4 h-4 mr-2" /> Change Photo
                <input type="file" accept="image/*" onChange={handlePhotoChange} className="absolute inset-0 opacity-0 cursor-pointer" />
